import React, { useState } from 'react';

const App = () => {
  const [message, setMessage] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="flex items-center">
        <img src="https://via.placeholder.com/50" alt="Profile Picture" className="w-10 h-10 rounded-full"/>
        <div className="ml-4">
          <h2 className="text-lg">John Doe</h2>
          <input
className="bg-[#B7D7CD] p-2 rounded focus:outline-none"
           value={message}
           onChange={(e) => setMessage(e.target.value)}
           placeholder="Message..." />
          <button className="bg-[#C06C88] p-2 rounded focus:outline-none ml-2" onClick={() => setIsTyping(true)}>Send</button>
        </div>
      </div>
      {isTyping && <div className="bg-[#C06C88] p-2 rounded ml-4">Typing...</div>}
    </div>
  );
};

export default App;
